+fn dfs_finish_order(
+    start: &str,
+    dependency_map: &HashMap<String, Vec<String>>,
+    visited: &mut HashSet<String>,
+    finish_order: &mut Vec<String>,
+) {
+    let mut stack = vec![(start.to_string(), false)];
+
+    while let Some((node_id, expanded)) = stack.pop() {
+        if expanded {
