+    assert!(
+        create_a.status.success(),
+        "create A failed: {}",
+        create_a.stderr
+    );
+    let create_b = run_br(&workspace, ["create", "Quiet dep B"], "create_b");
+    assert!(
+        create_b.status.success(),
+        "create B failed: {}",
+        create_b.stderr
+    );
+
+    let id_a = create_a
+        .stdout
+        .lines()
+        .next()
+        .unwrap_or("")
+        .strip_prefix("✓ Created ")
+        .and_then(|rest| rest.split(':').next())
+        .unwrap_or("")
+        .trim()
+        .to_string();
+    let id_b = create_b
+        .stdout
+        .lines()
+        .next()
+        .unwrap_or("")
+        .strip_prefix("✓ Created ")
+        .and_then(|rest| rest.split(':').next())
+        .unwrap_or("")
+        .trim()
+        .to_string();
+
+    let add = run_br(
+        &workspace,
+        ["--quiet", "dep", "add", &id_a, &id_b],
+        "dep_add_quiet",
